import{_ as t,c as i,o as a,a1 as o}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"AI App Factory Best Practices: Product Descriptions, Checkpoints, Scope & Iterative Development | Tutorial","description":"Master AI App Factory best practices to improve the quality and efficiency of AI-generated apps. Learn to write clear product descriptions, leverage checkpoints for quality control, define non-goals to prevent scope creep, iteratively validate ideas, save tokens with session splitting, and handle failures and retries. This tutorial covers input quality, checkpoint validation, MVP control, iterative development, context optimization, and failure handling.","frontmatter":{"title":"AI App Factory Best Practices: Product Descriptions, Checkpoints, Scope & Iterative Development | Tutorial","sidebarTitle":"Best Practices","subtitle":"Best Practices: Clear Descriptions, Checkpoint Utilization, Scope Control & Iterative Techniques","description":"Master AI App Factory best practices to improve the quality and efficiency of AI-generated apps. Learn to write clear product descriptions, leverage checkpoints for quality control, define non-goals to prevent scope creep, iteratively validate ideas, save tokens with session splitting, and handle failures and retries. This tutorial covers input quality, checkpoint validation, MVP control, iterative development, context optimization, and failure handling.","tags":["Best Practices","MVP","Iterative Development"],"prerequisite":["start-getting-started","start-pipeline-overview"],"order":200},"headers":[],"relativePath":"hyz1992/agent-app-factory/faq/best-practices/index.md","filePath":"hyz1992/agent-app-factory/faq/best-practices/index.md"}'),s={name:"hyz1992/agent-app-factory/faq/best-practices/index.md"};function n(r,e,l,c,d,p){return a(),i("div",null,[...e[0]||(e[0]=[o(`<h1 id="best-practices-clear-descriptions-checkpoint-utilization-scope-control-iterative-techniques" tabindex="-1">Best Practices: Clear Descriptions, Checkpoint Utilization, Scope Control &amp; Iterative Techniques <a class="header-anchor" href="#best-practices-clear-descriptions-checkpoint-utilization-scope-control-iterative-techniques" aria-label="Permalink to &quot;Best Practices: Clear Descriptions, Checkpoint Utilization, Scope Control &amp; Iterative Techniques&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><p>After completing this lesson, you will master:</p><ul><li>How to write high-quality product descriptions that help AI understand your ideas</li><li>How to leverage the checkpoint mechanism to control output quality at each stage</li><li>How to define scope boundaries through non-goals to prevent project bloat</li><li>How to quickly validate ideas and continuously optimize through step-by-step iteration</li></ul><h2 id="your-current-struggles" tabindex="-1">Your Current Struggles <a class="header-anchor" href="#your-current-struggles" aria-label="Permalink to &quot;Your Current Struggles&quot;">​</a></h2><p>Have you encountered these situations:</p><ul><li>&quot;I explained it clearly, why isn&#39;t the output what I wanted?&quot;</li><li>&quot;One small issue causes everything downstream to fail, making fixes painful&quot;</li><li>&quot;Features keep getting added during development, making it impossible to finish&quot;</li><li>&quot;Trying to build all features at once, but nothing gets done&quot;</li></ul><h2 id="when-to-use-this-approach" tabindex="-1">When to Use This Approach <a class="header-anchor" href="#when-to-use-this-approach" aria-label="Permalink to &quot;When to Use This Approach&quot;">​</a></h2><p>Whether you&#39;re using AI App Factory for the first time or have some experience, these best practices will help you:</p><ul><li><strong>Improve output quality</strong>: Make generated apps meet expectations</li><li><strong>Save modification time</strong>: Avoid error accumulation by discovering issues early</li><li><strong>Control project scale</strong>: Focus on MVP and deliver quickly</li><li><strong>Reduce development costs</strong>: Validate in stages to avoid wasted investment</li></ul><h2 id="🎒-prerequisites" tabindex="-1">🎒 Prerequisites <a class="header-anchor" href="#🎒-prerequisites" aria-label="Permalink to &quot;🎒 Prerequisites&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Requirements</p><ul><li>Read <a href="./../../start/getting-started/">Quick Start</a> to understand basic concepts of AI App Factory</li><li>Read <a href="./../../start/pipeline-overview/">7-Stage Pipeline Overview</a> to understand the complete process</li><li>Completed at least one full pipeline execution (so you have an intuitive feel for each stage&#39;s output)</li></ul></div><h2 id="core-principles" tabindex="-1">Core Principles <a class="header-anchor" href="#core-principles" aria-label="Permalink to &quot;Core Principles&quot;">​</a></h2><p>AI App Factory&#39;s best practices revolve around four core principles:</p><ol><li><strong>Input quality determines output quality</strong>: Clear, detailed product descriptions are the first step to success</li><li><strong>Checkpoints are quality barriers</strong>: Carefully validate after each stage to avoid error accumulation</li><li><strong>MVP focus</strong>: Define non-goals, control scope, and deliver core features quickly</li><li><strong>Continuous iteration</strong>: Validate core ideas first, then expand functionality gradually</li></ol><p>These principles are derived from source code and practical experience. Following them can improve your development efficiency several times over.</p><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="technique-1-provide-clear-product-descriptions" tabindex="-1">Technique 1: Provide Clear Product Descriptions <a class="header-anchor" href="#technique-1-provide-clear-product-descriptions" aria-label="Permalink to &quot;Technique 1: Provide Clear Product Descriptions&quot;">​</a></h3><h4 id="why" tabindex="-1">Why <a class="header-anchor" href="#why" aria-label="Permalink to &quot;Why&quot;">​</a></h4><p>When AI understands your ideas, it relies solely on the text information you provide. The clearer the description, the more the generated output meets expectations.</p><h4 id="how" tabindex="-1">How <a class="header-anchor" href="#how" aria-label="Permalink to &quot;How&quot;">​</a></h4><p><strong>A good product description includes these elements</strong>:</p><ul><li><strong>Target users</strong>: Who will use this product?</li><li><strong>Core problem</strong>: What difficulties are users facing?</li><li><strong>Solution</strong>: How does the product solve this difficulty?</li><li><strong>Key features</strong>: What features must be included?</li><li><strong>Use scenarios</strong>: In what situations do users use it?</li><li><strong>Constraints</strong>: What limitations or special requirements exist?</li></ul><h4 id="comparison-examples" tabindex="-1">Comparison Examples <a class="header-anchor" href="#comparison-examples" aria-label="Permalink to &quot;Comparison Examples&quot;">​</a></h4><table tabindex="0"><thead><tr><th>❌ Poor Description</th><th>✅ Good Description</th></tr></thead><tbody><tr><td>Make a fitness app</td><td>An app to help fitness beginners track workouts, supporting exercise type recording, duration, calories burned, and weekly workout statistics. Target users are young people just starting fitness. Core features are quick recording and progress viewing, without social sharing or payment features</td></tr><tr><td>Make a bookkeeping app</td><td>A mobile bookkeeping app to help young people quickly record daily expenses. Main features include recording amounts, selecting categories (food, transport, entertainment, other), and viewing monthly total expenses and category statistics. Supports offline use, data stored locally only</td></tr><tr><td>Make a task management tool</td><td>A simple tool to help small teams manage tasks, supporting task creation, member assignment, deadline setting, and task list viewing. Team members can share task status. No complex workflows or permission management needed</td></tr></tbody></table><h4 id="checklist-✅" tabindex="-1">Checklist ✅ <a class="header-anchor" href="#checklist-✅" aria-label="Permalink to &quot;Checklist ✅&quot;">​</a></h4><ul><li>[ ] Target users are clearly defined in the description</li><li>[ ] Core problem users face is explained in the description</li><li>[ ] Key features are listed in the description (no more than 5)</li><li>[ ] Description includes constraints or non-goals</li></ul><hr><h3 id="technique-2-carefully-validate-at-checkpoints" tabindex="-1">Technique 2: Carefully Validate at Checkpoints <a class="header-anchor" href="#technique-2-carefully-validate-at-checkpoints" aria-label="Permalink to &quot;Technique 2: Carefully Validate at Checkpoints&quot;">​</a></h3><h4 id="why-1" tabindex="-1">Why <a class="header-anchor" href="#why-1" aria-label="Permalink to &quot;Why&quot;">​</a></h4><p>The pipeline pauses at a checkpoint after completing each stage, waiting for your confirmation. This is a <strong>quality barrier</strong> that lets you discover issues early and prevent errors from propagating to subsequent stages.</p><p>If you discover an issue at this stage, you only need to rerun the current stage; if you wait until the end, you may need to roll back multiple stages, wasting significant time and tokens.</p><h4 id="how-1" tabindex="-1">How <a class="header-anchor" href="#how-1" aria-label="Permalink to &quot;How&quot;">​</a></h4><p><strong>When validating at each checkpoint, check the following</strong>:</p><p><strong>Bootstrap Stage Checkpoint</strong>:</p><ul><li>[ ] Problem definition in <code>input/idea.md</code> is accurate</li><li>[ ] Target user persona is clear and specific</li><li>[ ] Core value proposition is clear</li><li>[ ] Assumptions are reasonable</li></ul><p><strong>PRD Stage Checkpoint</strong>:</p><ul><li>[ ] User stories are clear and include acceptance criteria</li><li>[ ] Feature list does not exceed 7 items (MVP principle)</li><li>[ ] Non-goals are explicitly listed</li><li>[ ] Does not include technical details (such as React, API, database)</li></ul><p><strong>UI Stage Checkpoint</strong>:</p><ul><li>[ ] Page structure is reasonable, no more than 3 pages</li><li>[ ] Prototype can be previewed in browser</li><li>[ ] Interaction flow is clear</li><li>[ ] Aesthetic style is distinct (avoid common AI style)</li></ul><p><strong>Tech Stage Checkpoint</strong>:</p><ul><li>[ ] Tech stack selection is reasonable and follows MVP principle</li><li>[ ] Data model design is simple, number of tables does not exceed 10</li><li>[ ] API endpoint list is complete</li><li>[ ] No over-engineering like microservices or caching</li></ul><p><strong>Code Stage Checkpoint</strong>:</p><ul><li>[ ] Frontend and backend code structure is complete</li><li>[ ] Includes test cases</li><li>[ ] No obvious <code>any</code> types</li><li>[ ] Includes README.md explaining how to run</li></ul><p><strong>Validation Stage Checkpoint</strong>:</p><ul><li>[ ] No serious security issues in validation report</li><li>[ ] Test coverage &gt; 60%</li><li>[ ] No dependency installation conflicts</li><li>[ ] TypeScript type checking passes</li></ul><p><strong>Preview Stage Checkpoint</strong>:</p><ul><li>[ ] README.md includes complete running instructions</li><li>[ ] Docker configuration builds successfully</li><li>[ ] Frontend and backend services can start locally</li><li>[ ] Includes environment variable configuration instructions</li></ul><h4 id="checkpoint-validation-process" tabindex="-1">Checkpoint Validation Process <a class="header-anchor" href="#checkpoint-validation-process" aria-label="Permalink to &quot;Checkpoint Validation Process&quot;">​</a></h4><p>At each checkpoint, the system provides these options:</p><ul><li><strong>Continue</strong>: If the output meets expectations, proceed to the next stage</li><li><strong>Retry</strong>: If the output has issues, provide modification feedback and rerun the current stage</li><li><strong>Pause</strong>: If more information is needed or you want to adjust the idea, pause the pipeline</li></ul><p><strong>Decision Principles</strong>:</p><ul><li>✅ <strong>Continue</strong>: All checklist items meet requirements</li><li>⚠️ <strong>Retry</strong>: Minor issues (format, omissions, details) that can be immediately fixed</li><li>🛑 <strong>Pause</strong>: Major issues (wrong direction, scope out of control, cannot be fixed) that require re-planning</li></ul><h4 id="common-pitfalls" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h4><div class="danger custom-block"><p class="custom-block-title">Common Mistakes</p><p><strong>Don&#39;t skip checkpoint validation just to &quot;get it done quickly&quot;!</strong></p><p>The pipeline is designed to &quot;pause and validate at each stage&quot; precisely to let you discover issues in time. If you habitually click &quot;Continue&quot; and discover problems at the end, you may need to:</p><ul><li>Roll back multiple stages</li><li>Re-execute significant work</li><li>Waste large amounts of tokens</li></ul><p>Remember: <strong>Time invested in checkpoint validation is far less than the time cost of rolling back and redoing</strong>.</p></div><hr><h3 id="technique-3-control-scope-with-non-goals" tabindex="-1">Technique 3: Control Scope with Non-Goals <a class="header-anchor" href="#technique-3-control-scope-with-non-goals" aria-label="Permalink to &quot;Technique 3: Control Scope with Non-Goals&quot;">​</a></h3><h4 id="why-2" tabindex="-1">Why <a class="header-anchor" href="#why-2" aria-label="Permalink to &quot;Why&quot;">​</a></h4><p><strong>Non-goals are a core weapon for MVP development</strong>. Explicitly listing &quot;what not to do&quot; effectively prevents scope creep.</p><p>Many projects fail not because of too few features, but because of too many features. Each new feature adds complexity, development time, and maintenance cost. Define boundaries, focus on core value, and deliver quickly.</p><h4 id="how-2" tabindex="-1">How <a class="header-anchor" href="#how-2" aria-label="Permalink to &quot;How&quot;">​</a></h4><p><strong>In the Bootstrap stage, explicitly list non-goals</strong>:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Non-Goals (Features Not in This Version)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">1.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> No multi-user collaboration support</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">2.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> No real-time synchronization</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">3.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> No third-party service integration (such as payments, maps)</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">4.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> No data analytics or reporting features</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">5.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> No social sharing functionality</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">6.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> No user authentication or login functionality</span></span></code></pre></div><p><strong>In the PRD stage, make non-goals a separate section</strong>:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Non-Goals (Explicitly Not Doing This Version)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">The following features have value but are not within the scope of this MVP:</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Feature | Reason | Future Plan |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| --- | --- | --- |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Multi-user collaboration | Focus on individual users | Consider for v2.0 |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Real-time sync | Increases technical complexity | Consider after strong user feedback |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Payment integration | Not core value | Consider for v1.5 |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Data analytics | Not needed for MVP | Consider for v2.0 |</span></span></code></pre></div><h4 id="non-goal-judgment-criteria" tabindex="-1">Non-Goal Judgment Criteria <a class="header-anchor" href="#non-goal-judgment-criteria" aria-label="Permalink to &quot;Non-Goal Judgment Criteria&quot;">​</a></h4><p><strong>How to determine if something should be a non-goal</strong>:</p><ul><li>❌ This feature is not essential to validating the core idea → Make it a non-goal</li><li>❌ This feature significantly increases technical complexity → Make it a non-goal</li><li>❌ This feature can be replaced by manual means → Make it a non-goal</li><li>✅ This feature is the reason the product exists → Must include</li></ul><h4 id="common-pitfalls-1" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls-1" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h4><div class="warning custom-block"><p class="custom-block-title">Scope Creep Traps</p><p><strong>Common scope creep signals</strong>:</p><ol><li>&quot;It&#39;s simple anyway, let&#39;s just add one...&quot;</li><li>&quot;Competitors have this feature, so do we...&quot;</li><li>&quot;Users might need it, let&#39;s just build it first...&quot;</li><li>&quot;This feature is interesting, it can enhance product highlights...&quot;</li></ol><p><strong>When encountering these thoughts, ask yourself three questions</strong>:</p><ol><li>Is this feature useful for validating the core idea?</li><li>Can the product still work without this feature?</li><li>Will adding this feature delay delivery?</li></ol><p>If the answers are &quot;not needed,&quot; &quot;can work,&quot; and &quot;will delay,&quot; then decisively mark it as a non-goal.</p></div><hr><h3 id="technique-4-iterate-step-by-step-validate-quickly" tabindex="-1">Technique 4: Iterate Step-by-Step, Validate Quickly <a class="header-anchor" href="#technique-4-iterate-step-by-step-validate-quickly" aria-label="Permalink to &quot;Technique 4: Iterate Step-by-Step, Validate Quickly&quot;">​</a></h3><h4 id="why-3" tabindex="-1">Why <a class="header-anchor" href="#why-3" aria-label="Permalink to &quot;Why&quot;">​</a></h4><p><strong>The core principle of MVP (Minimum Viable Product) is to quickly validate ideas</strong>, not to build everything perfectly at once.</p><p>Through iterative development, you can:</p><ul><li>Get user feedback early</li><li>Adjust direction in time</li><li>Reduce sunk costs</li><li>Maintain development momentum</li></ul><h4 id="how-3" tabindex="-1">How <a class="header-anchor" href="#how-3" aria-label="Permalink to &quot;How&quot;">​</a></h4><p><strong>Steps for iterative development</strong>:</p><p><strong>Round 1: Core Feature Validation</strong></p><ol><li>Use AI App Factory to generate the first version of the app</li><li>Include only the 3-5 most core features</li><li>Run and test quickly</li><li>Show the prototype to real users and collect feedback</li></ol><p><strong>Round 2: Optimize Based on Feedback</strong></p><ol><li>Based on user feedback, determine the highest priority improvements</li><li>Modify <code>input/idea.md</code> or <code>artifacts/prd/prd.md</code></li><li>Use <code>factory run &lt;stage&gt;</code> to re-execute from the corresponding stage</li><li>Generate a new version and test</li></ol><p><strong>Round 3: Feature Expansion</strong></p><ol><li>Evaluate whether core goals are achieved</li><li>Select 2-3 high-value features</li><li>Generate and integrate through the pipeline</li><li>Iterate continuously and improve gradually</li></ol><h4 id="practical-iteration-example" tabindex="-1">Practical Iteration Example <a class="header-anchor" href="#practical-iteration-example" aria-label="Permalink to &quot;Practical Iteration Example&quot;">​</a></h4><p><strong>Scenario</strong>: You want to build a task management app</p><p><strong>Round 1 MVP</strong>:</p><ul><li>Core features: Create tasks, view list, mark complete</li><li>Non-goals: Member management, permission control, reminder notifications</li><li>Delivery time: 1 day</li></ul><p><strong>Round 2 Optimization</strong> (based on feedback):</p><ul><li>User feedback: Want to add tags to tasks</li><li>Modify PRD, add &quot;tag categorization&quot; feature</li><li>Re-execute pipeline from UI stage</li><li>Delivery time: Half a day</li></ul><p><strong>Round 3 Expansion</strong> (after successful validation):</p><ul><li>Add member management feature</li><li>Add deadline reminders</li><li>Add task comment feature</li><li>Delivery time: 2 days</li></ul><h4 id="checklist-✅-1" tabindex="-1">Checklist ✅ <a class="header-anchor" href="#checklist-✅-1" aria-label="Permalink to &quot;Checklist ✅&quot;">​</a></h4><p>Before each iteration, check:</p><ul><li>[ ] New features align with core goals</li><li>[ ] New features are supported by user demand</li><li>[ ] New features won&#39;t significantly increase complexity</li><li>[ ] Clear acceptance criteria exist</li></ul><hr><h2 id="advanced-techniques" tabindex="-1">Advanced Techniques <a class="header-anchor" href="#advanced-techniques" aria-label="Permalink to &quot;Advanced Techniques&quot;">​</a></h2><h3 id="technique-5-save-tokens-with-session-splitting" tabindex="-1">Technique 5: Save Tokens with Session Splitting <a class="header-anchor" href="#technique-5-save-tokens-with-session-splitting" aria-label="Permalink to &quot;Technique 5: Save Tokens with Session Splitting&quot;">​</a></h3><h4 id="why-4" tabindex="-1">Why <a class="header-anchor" href="#why-4" aria-label="Permalink to &quot;Why&quot;">​</a></h4><p>Running the pipeline for a long time causes context accumulation and consumes large amounts of tokens. <strong>Split-session execution</strong> allows each stage to have its own clean context, greatly reducing usage costs.</p><h4 id="how-4" tabindex="-1">How <a class="header-anchor" href="#how-4" aria-label="Permalink to &quot;How&quot;">​</a></h4><p><strong>At each checkpoint, choose &quot;Continue in new session&quot;</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Execute in a new command line window</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> continue</span></span></code></pre></div><p>The system will automatically:</p><ol><li>Read <code>.factory/state.json</code> to restore state</li><li>Launch a new Claude Code window</li><li>Continue from the next stage to be executed</li><li>Load only the input files needed for that stage</li></ol><p><strong>Comparison</strong>:</p><table tabindex="0"><thead><tr><th>Approach</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td>Continue in same session</td><td>Simple, no need to switch windows</td><td>Context accumulates, high token consumption</td></tr><tr><td>Continue in new session</td><td>Each stage gets clean context, saves tokens</td><td>Need to switch windows</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Recommended Practice</p><p><strong>For large projects or limited token budgets, we strongly recommend using &quot;Continue in new session&quot;</strong>.</p><p>For detailed explanations, see the <a href="./../../advanced/context-optimization/">Context Optimization</a> tutorial.</p></div><hr><h3 id="technique-6-handle-failures-and-retries" tabindex="-1">Technique 6: Handle Failures and Retries <a class="header-anchor" href="#technique-6-handle-failures-and-retries" aria-label="Permalink to &quot;Technique 6: Handle Failures and Retries&quot;">​</a></h3><h4 id="why-5" tabindex="-1">Why <a class="header-anchor" href="#why-5" aria-label="Permalink to &quot;Why&quot;">​</a></h4><p>During pipeline execution, you may encounter failures (insufficient input, permission issues, code errors, etc.). Understanding how to handle failures lets you recover progress more quickly.</p><h4 id="how-5" tabindex="-1">How <a class="header-anchor" href="#how-5" aria-label="Permalink to &quot;How&quot;">​</a></h4><p><strong>Best practices for failure handling</strong> (refer to <code>failure.policy.md:267-274</code>):</p><ol><li><strong>Fail early</strong>: Discover issues as early as possible to avoid wasting time in subsequent stages</li><li><strong>Detailed logging</strong>: Record sufficient context information for troubleshooting</li><li><strong>Atomic operations</strong>: Each stage&#39;s output should be atomic for easy rollback</li><li><strong>Preserve evidence</strong>: Archive failed artifacts before retrying for comparative analysis</li><li><strong>Progressive retry</strong>: Provide more specific guidance during retry rather than simple repetition</li></ol><p><strong>Common failure scenarios</strong>:</p><table tabindex="0"><thead><tr><th>Failure Type</th><th>Symptoms</th><th>Solution</th></tr></thead><tbody><tr><td>Missing output</td><td><code>input/idea.md</code> doesn&#39;t exist</td><td>Retry, check write path</td></tr><tr><td>Scope creep</td><td>Feature count &gt; 7</td><td>Retry, require simplification to MVP</td></tr><tr><td>Technical error</td><td>TypeScript compilation fails</td><td>Check type definitions, retry</td></tr><tr><td>Permission issue</td><td>Agent writes to unauthorized directory</td><td>Check capability boundary matrix</td></tr></tbody></table><p><strong>Failure recovery checklist</strong>:</p><ul><li>[ ] Failure cause is clear</li><li>[ ] Fix solution is implemented</li><li>[ ] Relevant configuration is updated</li><li>[ ] Restart from the failed stage</li></ul><div class="tip custom-block"><p class="custom-block-title">Failure is Normal</p><p><strong>Don&#39;t fear failure!</strong> AI App Factory is designed with robust failure handling mechanisms:</p><ul><li>Each stage allows one automatic retry</li><li>Failed artifacts are automatically archived to <code>artifacts/_failed/</code></li><li>Can roll back to the most recent successful checkpoint</li></ul><p>When encountering failures, calmly analyze the cause and handle according to the failure strategy.</p></div><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>This lesson introduced six best practices for AI App Factory:</p><ol><li><strong>Clear product descriptions</strong>: Detail target users, core problems, key features, and constraints</li><li><strong>Careful checkpoint validation</strong>: Check output quality after each stage to avoid error accumulation</li><li><strong>Control scope with non-goals</strong>: Explicitly list features not to do, prevent scope creep</li><li><strong>Step-by-step iteration</strong>: Validate core ideas first, then expand gradually based on user feedback</li><li><strong>Save tokens with session splitting</strong>: Create new sessions at each checkpoint, reduce usage costs</li><li><strong>Handle failures correctly</strong>: Leverage failure handling mechanisms to quickly recover progress</li></ol><p>Following these best practices will make your AI App Factory experience smoother, generate higher quality apps, and improve development efficiency several times over.</p><hr><h2 id="next-up" tabindex="-1">Next Up <a class="header-anchor" href="#next-up" aria-label="Permalink to &quot;Next Up&quot;">​</a></h2><blockquote><p>In the next lesson, we will learn <strong><a href="./../../appendix/cli-commands/">CLI Command Reference</a></strong>.</p><p>You will learn:</p><ul><li>All parameters and options for the <code>factory init</code> command</li><li>How the <code>factory run</code> command starts from a specified stage</li><li>How the <code>factory continue</code> command continues in a new session</li><li>How <code>factory status</code> and <code>factory list</code> view project information</li><li>How <code>factory reset</code> resets project state</li></ul></blockquote><hr><h2 id="appendix-source-code-references" tabindex="-1">Appendix: Source Code References <a class="header-anchor" href="#appendix-source-code-references" aria-label="Permalink to &quot;Appendix: Source Code References&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Updated: 2026-01-29</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Line Numbers</th></tr></thead><tbody><tr><td>Product description techniques</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/README.md#L186-L210" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>186-210</td></tr><tr><td>Checkpoint mechanism</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/agents/orchestrator.checkpoint.md#L98-L112" target="_blank" rel="noreferrer"><code>agents/orchestrator.checkpoint.md</code></a></td><td>98-112</td></tr><tr><td>Non-goal control</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/README.md#L199-L203" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>199-203</td></tr><tr><td>Failure handling strategy</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/failure.policy.md#L267-L274" target="_blank" rel="noreferrer"><code>policies/failure.policy.md</code></a></td><td>267-274</td></tr><tr><td>Context isolation</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/context-isolation.md#L10-L42" target="_blank" rel="noreferrer"><code>policies/context-isolation.md</code></a></td><td>10-42</td></tr><tr><td>Code standards</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/code-standards.md" target="_blank" rel="noreferrer"><code>policies/code-standards.md</code></a></td><td>Full document</td></tr></tbody></table><p><strong>Key Constants</strong>:</p><ul><li><code>MAX_RETRY_COUNT = 1</code>: Each stage allows one automatic retry by default</li></ul><p><strong>Key Rules</strong>:</p><ul><li>Must Have features ≤ 7 (MVP principle)</li><li>Page count ≤ 3 pages (UI stage)</li><li>Data model count ≤ 10 (Tech stage)</li><li>Test coverage &gt; 60% (Validation stage)</li></ul></details>`,131)])])}const g=t(s,[["render",n]]);export{u as __pageData,g as default};
